     1→import { Injectable, Logger } from '@nestjs/common';
     2→
     3→import { AlgoliaService } from '@modules/algolia/algolia.service';
     4→import { CondensedFeaturesService } from '@modules/db/condensed-features/condensed-features.service';
     5→import { ICondensedFeaturesBase } from '@modules/db/condensed-features/types/condensed-features.base.interface';
     6→import { ProductAnnualSalesService } from '@modules/db/product-annual-sales/product-annual-sales.service';
