    39→@Injectable()
    40→export class ProcessStyleService {
    41→	private readonly logger = new Logger(ProcessStyleService.name);
    42→	private readonly mmsImagesLambdaHost = getEnv({ key: MMS_IMAGES_LAMBDA_HOST });
    43→
    44→	constructor(
    45→		private readonly stylesHashService: StylesHashService,
    46→		private readonly condensedFeaturesService: CondensedFeaturesService,
    47→		private readonly OpenAIService: OpenAIService,
    48→		private readonly algoliaService: AlgoliaService,
    49→		private readonly mmsService: MmsService,
    50→		private readonly productAnnualSalesService: ProductAnnualSalesService,
    51→		private readonly stylesService: StylesService,
    52→	) {}
    53→
    54→	@LogExecution({
    55→		paramFormatter: (params) => params,
    56→		responseFormatter: (response) => response,
    57→		logErrToRollbar: false,
    58→		logParams: false,
    59→		logResponse: false,
    60→		logLongExecution: false,
