    62→	public async process({
    63→		style,
    64→		allCategories,
    65→	}: {
    66→		style: MMSStyleToProcess;
    67→		allCategories: MMSAllStyleCategory[];
    68→	}): Promise<boolean> {
    69→		try {
    70→			if (!this.isProductAllowedToProcess(style)) {
    71→				this.logger.debug(`Style ${style.id} is not allowed to process.`);
    72→				await Promise.all([
    73→					this.deleteFromAlgoliaIndex({ styleId: style.id }),
    74→					this.deleteCondensedFeatures({ styleId: style.id }),
    75→				]);
    76→				return false;
    77→			}
    78→
    79→			if (!style.colors?.length) {
    80→				this.logger.debug(`Style ${style.id} has no colors, skipping processing.`);
    81→				return false;
    82→			}
    83→
    84→			const featuresRelatedFields = this.extractFeaturesRelatedFields({
    85→				style,
    86→				allCategories,
    87→			});
    88→
    89→			const isProductActive = this.checkIsProductActive({
    90→				status: style.status,
    91→				colors: style.colors,
    92→			});
    93→
    94→			await this.saveStyleToDatabase({ style, allCategories, isProductActive });
    95→
    96→			const newHash = hashFromObject({
    97→				obj: featuresRelatedFields as unknown as Record<string, unknown>,
    98→			});
    99→			const storedHash = await this.getStoredHash({ styleId: style.id });
   100→
   101→			const isCondensedFeaturesExists =
   102→				await this.condensedFeaturesService.getCondensedFeature({
   103→					styleId: style.id,
   104→				});
   105→
   106→			if (!storedHash) {
   107→				if (!isCondensedFeaturesExists) {
   108→					this.logger.debug(
   109→						`Style ${style.id}: no hash, no features. Creating new features`,
   110→					);
   111→
   112→					const condensedFeatures = isProductActive
   113→						? await this.generateLLMFeatures({ style, featuresRelatedFields })
   114→						: [];
   115→					await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
   116→					await this.createHash({ styleId: style.id, hash: newHash });
   117→					await this.updateAlgoliaIndex({
   118→						style,
   119→						allCategories,
   120→						condensedFeatures,
   121→					});
   122→				} else {
   123→					this.logger.debug(
   124→						`Style ${style.id}: no hash, but features exist. Generating hash`,
   125→					);
   126→					await this.createHash({ styleId: style.id, hash: newHash });
   127→					await this.updateAlgoliaIndex({
   128→						style,
   129→						allCategories,
   130→						condensedFeatures: isCondensedFeaturesExists.condensed_features,
   131→					});
   132→				}
   133→
   134→				return true;
   135→			} else if (storedHash && !compareHashes({ hash1: newHash, hash2: storedHash })) {
   136→				this.logger.debug(`Style ${style.id}: hash changed, updating features and index`);
   137→
   138→				const condensedFeatures = isProductActive
   139→					? await this.generateLLMFeatures({ style, featuresRelatedFields })
   140→					: (isCondensedFeaturesExists?.condensed_features ?? []);
   141→				await this.updateStoredHash({ styleId: style.id, hash: newHash });
   142→				await this.updateCondensedFeatures({ styleId: style.id, condensedFeatures });
   143→				await this.updateAlgoliaIndex({
   144→					style,
   145→					allCategories,
   146→					condensedFeatures,
   147→				});
   148→				return true;
   149→			} else if (storedHash && !isCondensedFeaturesExists) {
   150→				this.logger.debug(
   151→					`Style ${style.id}: hash exists, but no features exist. Creating new features`,
   152→				);
   153→				const condensedFeatures = isProductActive
   154→					? await this.generateLLMFeatures({ style, featuresRelatedFields })
   155→					: [];
   156→				await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
   157→				await this.updateAlgoliaIndex({
   158→					style,
   159→					allCategories,
   160→					condensedFeatures,
   161→				});
   162→				return true;
   163→			}
   164→
   165→			await this.updateAlgoliaIndex({
   166→				style,
   167→				allCategories,
   168→				condensedFeatures: isCondensedFeaturesExists?.condensed_features ?? [],
   169→			});
   170→			this.logger.debug(`Style ${style.id}: hash is the same, no changes needed`);
   171→			return false;
   172→		} catch (error) {
   173→			this.logger.error(`Error processing style ${style.id}:`, error);
   174→			throw error;
   175→		}
   176→	}
