   194→	private checkIsProductActive({
   195→		status,
   196→		colors,
   197→	}: {
   198→		status: string;
   199→		colors: MMSStyleToProcess['colors'];
   200→	}): boolean {
   201→		if (status === styleStatus.ACTIVE) {
   202→			if (colors?.length) {
   203→				return colors.some((color) => color.status === styleStatus.ACTIVE);
   204→			}
   205→
   206→			return true;
   207→		}
   208→
   209→		return false;
   210→	}
