   212→	private isProductAllowedToProcess(style: MMSStyleToProcess): boolean {
   213→		const name = String(style.name);
   214→		const formattedName = name.toLowerCase();
   215→		const isCanadian =
   216→			formattedName.includes('canada') || formattedName.includes('canadian');
   217→
   218→		return !isCanadian;
   219→	}
