   221→	private async getStoredHash({
   222→		styleId,
   223→	}: {
   224→		styleId: number;
   225→	}): Promise<IStylesHashBase['hash'] | null> {
   226→		const hashRecord = await this.stylesHashService.getStyleHash({ styleId });
   227→
   228→		if (!hashRecord) {
   229→			this.logger.debug(`No stored hash found for style ${styleId}`);
   230→			return null;
   231→		}
   232→
   233→		return hashRecord.hash;
