   253→	private async updateStoredHash({
   254→		styleId,
   255→		hash,
   256→	}: {
   257→		styleId: number;
   258→		hash: string;
   259→	}): Promise<void> {
   260→		await this.stylesHashService.updateHashValue({
   261→			styleId,
   262→			hash,
   263→			algorithm: STYLES_HASHING_ALGORITHM,
