   268→	private async saveStyleToDatabase({
   269→		style,
   270→		allCategories,
   271→		isProductActive,
   272→	}: {
   273→		style: MMSStyleToProcess;
   274→		allCategories: MMSAllStyleCategory[];
   275→		isProductActive: boolean;
   276→	}): Promise<void> {
   277→		try {
   278→			const categoryIds = this.extractCategoryIds({ style });
   279→			const categoriesWithParentsIds = this.extractCategoriesWithParents({
   280→				categoryIds,
   281→				allCategories,
   282→			});
   283→
   284→			const purchasesCount =
   285→				await this.productAnnualSalesService.getPurchasesCountForLatestYear({
   286→					styleId: Number(style.id),
   287→				});
   288→
   289→			const styleData = {
   290→				style_id: style.id,
   291→				primary_category_id: style.primary_category_id ?? 0,
   292→				root_category_id: this.getRootCategoryId({ style, allCategories }),
   293→				purchases_count: purchasesCount,
   294→				categories_ids: categoryIds,
   295→				categories_with_parents_ids: categoriesWithParentsIds,
   296→				is_active: isProductActive,
   297→				name: style.name,
   298→				decoration_method: style.decoration_method,
   299→				features: style.features,
   300→				general_comments: style.general_comments,
   301→				manufacturer: style.manufacturer,
   302→				minimum_quantity: style.min_qty,
   303→				rating_count: style.rating_count,
   304→				rating_score: Number(style.rating_score),
   305→				sizes: (style.style_sizes ?? []).map((size) => size.name),
   306→				style_type: style.style_type,
   307→				price_level: style.price_level,
   308→				primary_category_name: style.primary_category?.name ?? '',
   309→				default_quote_qty: style.primary_category?.default_quote_qty ?? 1,
   310→				product_type: style.product_type,
   311→				style_card_image_url: this.generateStyleCardImageUrl({
   312→					styleId: style.id,
   313→					catalogDetailImageMd5: style.catalog_detail_image_md5,
   314→				}),
   315→				broad_category_names: this.getBroadCategoryNames({
   316→					categories: style.categories,
   317→					allCategories,
   318→				}),
   319→				sub_category_names: this.getStylesSubcategories({
   320→					categories: style.categories,
   321→					allCategories,
   322→				}),
   323→				turn_time: style.turntime ? Number(style.turntime.standard) : 0,
   324→				rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
   325→				no_minimum: style.has_singles_enabled_colors,
   326→				link_path: this.calculateLink({ style, allCategories })?.path ?? '',
   327→				brand: this.getBrand([style.brand]),
   328→				min_qty: style.min_qty,
   329→			};
   330→
   331→			if (!style.colors?.length) {
   332→				this.logger.debug(`Style ${style.id} has no colors to save`);
   333→				return;
   334→			}
   335→
   336→			const colors = style.colors.map((color) => {
   337→				const isActive = color.status === styleStatus.ACTIVE;
   338→				const hasRgb = Array.isArray(color.rbgs) && color.rbgs[0];
   339→				const colorRgb =
   340→					hasRgb && color.rbgs[0] ? convertRGBToString(color.rbgs[0]) : null;
   341→
   342→				return {
   343→					color_id: color.id,
   344→					color_rgb: colorRgb,
   345→					color_name: color.name,
   346→					is_active: Boolean(isActive && hasRgb),
   347→					image_url: color.image_url,
   348→				};
   349→			});
   350→
   351→			const defaultUnitPrices = this.getDefaultUnitPrices({ style }).map((priceData) => ({
   352→				quantity: priceData.quantity,
   353→				price: Number(priceData.price),
   354→				regular_unit_price: priceData.regular_unit_price
   355→					? Number(priceData.regular_unit_price)
   356→					: null,
   357→				algorithm: priceData.algorithm,
   358→			}));
   359→
   360→			await this.stylesService.saveCompleteStyle({
   361→				styleData,
   362→				colors,
   363→				defaultUnitPrices,
   364→			});
   365→
   366→			this.logger.debug(`Successfully saved style ${style.id} to database`);
   367→		} catch (error: unknown) {
   368→			const err = error instanceof Error ? error : new Error(String(error));
   369→			this.logger.error(`Failed to save style ${style.id} to database: ${err.message}`);
   370→			throw err;
   371→		}
   372→	}
