   374→	private async generateLLMFeatures({
   375→		style,
   376→		featuresRelatedFields,
   377→	}: {
   378→		style: MMSStyleToProcess;
   379→		featuresRelatedFields: FeaturesRelatedFields;
   380→	}): Promise<string[]> {
   381→		try {
   382→			const result = await withRetry({
   383→				fn: () => this.OpenAIService.generateProductFeatures({ productInfo: style }),
   384→				options: { retryCount: 2 },
   385→			});
   386→
   387→			if (result.error) {
   388→				this.logger.error(
   389→					`Failed to generate features for style ${style.id}: ${result.error}`,
   390→				);
   391→				throw new Error(`Failed to generate features: ${result.error}`);
   392→			}
   393→
   394→			return result.description ?? [];
   395→		} catch (error) {
   396→			const errorMessage = error instanceof Error ? error.message : String(error);
   397→			const isTokenLimitError = errorMessage.includes('maximum context length');
   398→
   399→			if (isTokenLimitError) {
   400→				this.logger.warn(
   401→					`Token limit exceeded for style ${style.id}, retrying with reduced fields`,
   402→				);
   403→
   404→				const reducedResult = await withRetry({
   405→					fn: () =>
   406→						this.OpenAIService.generateProductFeatures({
   407→							productInfo: featuresRelatedFields as unknown as MMSStyleToProcess,
   408→						}),
   409→					options: { retryCount: 2 },
   410→				});
   411→
   412→				if (reducedResult.error) {
   413→					throw new Error(`Failed to generate features: ${reducedResult.error}`);
   414→				}
   415→
   416→				this.logger.log(
   417→					`Successfully generated features for style ${style.id} using reduced fields`,
   418→				);
   419→				return reducedResult.description ?? [];
   420→			}
   421→
   422→			this.logger.error(`Failed to generate features for style ${style.id}:`, error);
   423→			throw error;
   424→		}
   425→	}
