   469→	private async updateAlgoliaIndex({
   470→		style,
   471→		allCategories,
   472→		condensedFeatures,
   473→	}: {
   474→		style: MMSStyleToProcess;
   475→		allCategories: MMSAllStyleCategory[];
   476→		condensedFeatures?: string[];
   477→	}): Promise<void> {
   478→		const algoliaStyle = {
   479→			objectID: String(style.id),
   480→			name: style.name,
   481→			primary_category_id: style.primary_category_id,
   482→			brand: this.getBrand([style.brand]),
   483→			condensed_features: condensedFeatures ?? [],
   484→			sub_category_names: this.getStylesSubcategories({
   485→				categories: style.categories,
   486→				allCategories,
   487→			}),
   488→			no_minimum: style.has_singles_enabled_colors ? 1 : 0,
   489→			price_level: style.price_level,
   490→			product_id: style.id,
   491→			product_type: style.product_type,
   492→			style_card_image_url: this.generateStyleCardImageUrl({
   493→				styleId: style.id,
   494→				catalogDetailImageMd5: style.catalog_detail_image_md5,
   495→			}),
   496→		};
   497→
   498→		const objects = ALGOLIA_OBJECT_ID_SUFFIXES.map((suffix) => ({
   499→			...algoliaStyle,
   500→			objectID: `${style['objectID']}-${suffix}`,
   501→			index_suffix: suffix,
   502→		}));
   503→
   504→		await this.algoliaService.saveObjects({ objects });
   505→	}
