   507→	private async deleteFromAlgoliaIndex({ styleId }: { styleId: number }): Promise<void> {
   508→		const objectIds = ALGOLIA_OBJECT_ID_SUFFIXES.map((suffix) => `${styleId}-${suffix}`);
   509→		await this.algoliaService.deleteObjects({ objectIds });
   510→		this.logger.debug(`Deleted style ${styleId} from Algolia index (all suffixes)`);
   511→	}
