   518→		allCategories: MMSAllStyleCategory[];
   519→	}): FeaturesRelatedFields {
   520→		return {
   521→			name: style.name,
   522→			decoration_method: style.decoration_method,
   523→			features: style.features,
   524→			general_comments: style.general_comments,
   525→			manufacturer: style.manufacturer,
   526→			sizes: (style.style_sizes ?? []).map((size) => size.name),
   527→			style_type: style.style_type,
   528→			price_level: style.price_level,
   529→			primary_category_name: style.primary_category?.name ?? '',
   530→			product_type: style.product_type,
   531→			broad_category_names: this.getBroadCategoryNames({
   532→				categories: style.categories,
   533→				allCategories,
   534→			}),
   535→			sub_category_names: this.getStylesSubcategories({
   536→				categories: style.categories,
   537→				allCategories,
   538→			}),
   539→			turn_time: style.turntime ? Number(style.turntime.standard) : 0,
   540→			rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
   541→			no_minimum: style.has_singles_enabled_colors ? 1 : 0,
   542→		};
   543→	}
