   545→	private getDefaultUnitPrices({
   546→		style,
   547→	}: {
   548→		style: MMSStyleToProcess;
   549→	}): MMSStyleToProcess['default_unit_prices'] {
   550→		return style.default_unit_prices.reduce<MMSStyleToProcess['default_unit_prices']>(
   551→			(acc, pricesObj) => {
   552→				if (pricesObj.algorithm !== DEFAULT_PRICING_ALGORITHM) {
   553→					return acc;
   554→				}
   555→
   556→				acc.push({
   557→					quantity: pricesObj.quantity,
   558→					price: pricesObj.price,
   559→					algorithm: pricesObj.algorithm,
   560→					regular_unit_price: pricesObj.regular_unit_price ?? null,
   561→				});
   562→
   563→				return acc;
   564→			},
   565→			[],
   566→		);
   567→	}
