   569→	private generateStyleCardImageUrl({
   570→		styleId,
   571→		catalogDetailImageMd5,
   572→	}: {
   573→		styleId: number;
   574→		catalogDetailImageMd5: string | null;
   575→	}): string {
   576→		const basePath = '/mms/images/catalog/';
   577→		const md5Path = catalogDetailImageMd5 ? `${catalogDetailImageMd5}/` : '';
   578→		const stylePath = `styles/${styleId}/catalog_detail_image_medium.jpg`;
   579→
   580→		return `${this.mmsImagesLambdaHost}${basePath}${md5Path}${stylePath}`;
