   583→	private getBroadCategoryNames({
   584→		categories,
   585→		allCategories,
   586→	}: {
   587→		styleId?: number;
   588→		categories: MMSStyleToProcess['categories'];
   589→		allCategories: MMSAllStyleCategory[];
   590→	}): string[] {
   591→		const activeCategories = categories
   592→			.map((cat) => {
   593→				const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
   594→				if (fullCategory) {
   595→					cat['parent'] = fullCategory;
   596→				}
   597→				return cat;
   598→			})
   599→			.filter((cat) => cat.active);
   600→
   601→		const allParents = activeCategories
   602→			.map((category) => category['parent'] ?? { ...category, _id: category.id })
   603→			.filter(Boolean) as MMSAllStyleCategory[];
   604→
   605→		const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
   606→			if (TAXONOMY_CAT_IDS.includes(parent._id)) {
   607→				return acc;
   608→			}
   609→
   610→			if (!acc.some((p) => p._id === parent._id)) {
   611→				acc.push(parent);
   612→			}
   613→
   614→			return acc;
   615→		}, []);
   616→
   617→		const names = uniqueParents
   618→			.map((parent) => parent['name'])
   619→			.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];
   620→
   621→		return [...new Set(names)];
   622→	}
