   624→	private getStylesSubcategories({
   625→		categories,
   626→		allCategories,
   627→	}: {
   628→		categories: MMSStyleToProcess['categories'];
   629→		allCategories: MMSAllStyleCategory[];
   630→	}): string[] {
   631→		const activeCategories = categories.filter((cat) => cat.active && cat.parent_id);
   632→
   633→		const childCategories: string[] = [];
   634→
   635→		for (const category of activeCategories) {
   636→			const hasChildren = allCategories.some((cat) => cat['parent_id'] === category.id);
   637→
   638→			if (!hasChildren && category.name) {
   639→				childCategories.push(category.name);
   640→			}
   641→		}
   642→
   643→		return [...new Set(childCategories)];
   644→	}
