   650→	private calculateLink({
   651→		style,
   652→		allCategories,
   653→	}: {
   654→		style: MMSStyleToProcess;
   655→		allCategories: MMSAllStyleCategory[];
   656→	}): Breadcrumb | null {
   657→		function urlFriendly(str: string): string {
   658→			return str
   659→				.toLowerCase()
   660→				.replace(/&reg;/g, '®')
   661→				.replace(/\//g, '-')
   662→				.replace(/\s+/g, '-')
   663→				.replace(/[^\+\-0-9_a-z]/g, '')
   664→				.replace(/^-+|-+$/g, '')
   665→				.replace(/-+/g, '-');
   666→		}
   667→
   668→		const primaryCategory = style.primary_category;
   669→
   670→		if (!primaryCategory) {
   671→			return null;
   672→		}
   673→
   674→		const primaryCatParent = allCategories.find(
   675→			(cat) => cat._id === primaryCategory.parent_id,
   676→		);
   677→
   678→		const primaryCatParentName = primaryCatParent?.['name'] as string;
   679→		const categoryName = primaryCategory.name;
   680→
   681→		const firstPartLink = !primaryCatParent
   682→			? '/products'
   683→			: `/products/${urlFriendly(primaryCatParentName)}`;
   684→
   685→		const path = `${firstPartLink}/${urlFriendly(categoryName)}/${urlFriendly(style.name)}/${style.id}`;
   686→
   687→		return {
   688→			name: style.name,
   689→			path: path,
   690→		};
   691→	}
