   698→	private extractCategoriesWithParents({
   699→		categoryIds,
   700→		allCategories,
   701→	}: {
   702→		categoryIds: number[];
   703→		allCategories: MMSAllStyleCategory[];
   704→	}): number[] {
   705→		const allCategoryIds = new Set<number>();
   706→
   707→		for (const categoryId of categoryIds) {
   708→			allCategoryIds.add(categoryId);
   709→
   710→			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
   711→			for (const parentId of parentIds) {
   712→				allCategoryIds.add(parentId);
   713→			}
   714→		}
   715→
   716→		return Array.from(allCategoryIds).sort((a, b) => a - b);
   717→	}
   718→
   719→	private getAllParentCategoryIds({
   720→		categoryId,
   721→		allCategories,
   722→	}: {
   723→		categoryId: number;
   724→		allCategories: MMSAllStyleCategory[];
   725→	}): number[] {
   726→		const parents: number[] = [];
   727→		const category = allCategories.find((cat) => cat._id === categoryId);
   728→
   729→		if (!category?.['parent_id']) {
   730→			return parents;
   731→		}
   732→
   733→		let currentParentId = category['parent_id'] as number;
   734→
   735→		while (currentParentId) {
   736→			parents.push(currentParentId);
   737→
   738→			const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
   739→			if (!parentCategory?.['parent_id']) {
   740→				break;
   741→			}
   742→
   743→			currentParentId = parentCategory['parent_id'] as number;
   744→		}
   745→
   746→		return parents;
   747→	}
   748→
   749→	private getRootCategoryId({
   750→		style,
   751→		allCategories,
   752→	}: {
   753→		style: MMSStyleToProcess;
   754→		allCategories: MMSAllStyleCategory[];
   755→	}): number | null {
   756→		if (!style.primary_category) {
   757→			return null;
   758→		}
   759→
   760→		const primaryCategory = allCategories.find(
   761→			(cat) => cat._id === style.primary_category_id,
   762→		);
   763→		if (!primaryCategory) {
   764→			return null;
   765→		}
   766→
   767→		let currentCategory = primaryCategory;
   768→		while (currentCategory['parent_id']) {
   769→			const parentCategory = allCategories.find(
   770→				(cat) => cat._id === currentCategory['parent_id'],
   771→			);
   772→			if (!parentCategory) break;
   773→			currentCategory = parentCategory;
   774→		}
   775→
   776→		return !currentCategory['parent_id'] ? currentCategory._id : null;
   777→	}
   778→}
