				const leafCategory: MMSAllStyleCategory = {
					_id: 3,
					id: 3,
					active: true,
					name: 'Leaf',
					parent_id: 2,
					default_quote_qty: 25,
				};

				const style = buildStyle({
					primary_category_id: 3,
					categories: [
						{ id: 3, active: true, name: 'Leaf', parent_id: 2, default_quote_qty: 25 },
					],
				});

				const allCategories: MMSAllStyleCategory[] = [rootCategory, midCategory, leafCategory];

				await service.process({ style, allCategories });

				expect(mockStylesService.saveCompleteStyle).toHaveBeenCalledTimes(1);
			});
		});

		describe('calculateLink and getRootCategoryId', () => {
			it('should handle style with no primary_category for calculateLink', async () => {
				mockStylesHashService.getStyleHash.mockResolvedValue(null);
				mockCondensedFeaturesService.getCondensedFeature.mockResolvedValue(null);

				const style = buildStyle({ primary_category: null, primary_category_id: null });
				const allCategories: MMSAllStyleCategory[] = [];

				await service.process({ style, allCategories });

				expect(mockStylesService.saveCompleteStyle).toHaveBeenCalledTimes(1);
			});

			it('should build link with parent category when parent exists', async () => {
				mockStylesHashService.getStyleHash.mockResolvedValue(null);
				mockCondensedFeaturesService.getCondensedFeature.mockResolvedValue(null);

				const parentCat: MMSAllStyleCategory = {
					_id: 1,
					id: 1,
					active: true,
					name: 'Apparel',
					parent_id: 0,
					default_quote_qty: 25,
				};

				const style = buildStyle({
					primary_category: {
						id: 2,
						active: true,
						name: 'T-Shirts',
						parent_id: 1,
						default_quote_qty: 25,
					},
					primary_category_id: 2,
				});

				const allCategories: MMSAllStyleCategory[] = [
					parentCat,
					{ _id: 2, id: 2, active: true, name: 'T-Shirts', parent_id: 1, default_quote_qty: 25 },
				];

				await service.process({ style, allCategories });

				expect(mockStylesService.saveCompleteStyle).toHaveBeenCalledTimes(1);
			});

			it('should traverse parent chain for getRootCategoryId', async () => {
				mockStylesHashService.getStyleHash.mockResolvedValue(null);
				mockCondensedFeaturesService.getCondensedFeature.mockResolvedValue(null);

				const root: MMSAllStyleCategory = {
					_id: 1,
					id: 1,
					active: true,
					name: 'Root',
					parent_id: 0,
					default_quote_qty: 25,
				};

				const mid: MMSAllStyleCategory = {
					_id: 2,
					id: 2,
					active: true,
					name: 'Mid',
					parent_id: 1,
					default_quote_qty: 25,
				};

				const style = buildStyle({
					primary_category: {
						id: 2,
						active: true,
						name: 'Mid',
						parent_id: 1,
						default_quote_qty: 25,
					},
					primary_category_id: 2,
				});

				const allCategories: MMSAllStyleCategory[] = [root, mid];

				await service.process({ style, allCategories });

				expect(mockStylesService.saveCompleteStyle).toHaveBeenCalledTimes(1);
			});

			it('should return null from getRootCategoryId when primary category not in allCategories', async () => {
