				mockStylesHashService.getStyleHash.mockResolvedValue(null);
				mockCondensedFeaturesService.getCondensedFeature.mockResolvedValue(null);

				const style = buildStyle({
					default_unit_prices: [
						{ algorithm: 'some-other-algorithm', quantity: 10, price: '5.99' },
