	describe('private methods accessed directly', () => {
		describe('checkIsProductActive', () => {
			it('should return true when status is active and colors is null', () => {
				const result = (service as any).checkIsProductActive({
					status: styleStatus.ACTIVE,
					colors: null,
				});
				expect(result).toBe(true);
			});

			it('should return true when status is active and colors is empty array', () => {
				const result = (service as any).checkIsProductActive({
					status: styleStatus.ACTIVE,
					colors: [],
				});
				expect(result).toBe(true);
			});

			it('should return false when status is inactive', () => {
				const result = (service as any).checkIsProductActive({
					status: styleStatus.INACTIVE,
					colors: [buildColor({ status: styleStatus.ACTIVE })],
				});
				expect(result).toBe(false);
			});
		});

		describe('saveStyleToDatabase', () => {
			it('should return early without saving when colors is null', async () => {
				const style = buildStyle({ colors: null });
				const allCategories: MMSAllStyleCategory[] = [];

				await (service as any).saveStyleToDatabase({
					style,
					allCategories,
					isProductActive: true,
				});

				expect(mockStylesService.saveCompleteStyle).not.toHaveBeenCalled();
			});

			it('should return early without saving when colors is empty array', async () => {
				const style = buildStyle({ colors: [] });
				const allCategories: MMSAllStyleCategory[] = [];

				await (service as any).saveStyleToDatabase({
					style,
					allCategories,
					isProductActive: true,
				});

				expect(mockStylesService.saveCompleteStyle).not.toHaveBeenCalled();
			});

			it('should save style when colors are present', async () => {
				const style = buildStyle();
				const allCategories: MMSAllStyleCategory[] = [];

				await (service as any).saveStyleToDatabase({
					style,
					allCategories,
					isProductActive: true,
				});

				expect(mockStylesService.saveCompleteStyle).toHaveBeenCalledTimes(1);
			});

			it('should rethrow errors as Error objects when non-Error thrown', async () => {
				mockStylesService.saveCompleteStyle.mockRejectedValue('string error');

				const style = buildStyle();
				const allCategories: MMSAllStyleCategory[] = [];

				await expect(
					(service as any).saveStyleToDatabase({
						style,
						allCategories,
						isProductActive: true,
					}),
				).rejects.toThrow('string error');
			});
		});
	});
